#!/usr/bin/env python3\nimport json\nimport subprocess\nimport tempfile\nfrom pathlib import Path\n\nROOT = Path(__file__).resolve().parents[1]\nWORK = Path(tempfile.mkdtemp(prefix='paper-router-smoke-'))\n\n\ndef run(cmd):\n    res = subprocess.run(cmd, text=True, capture_output=True)\n    if res.returncode != 0:\n        raise SystemExit(f'Command failed: {cmd}\nSTDOUT:\n{res.stdout}\nSTDERR:\n{res.stderr}')\n    return res\n\n\ndef main():\n    intake = WORK / 'intake.json'\n    task = WORK / 'task.json'\n    plan = WORK / 'figure-plan.json'\n    draft = WORK / 'draft.md'\n    fixed = WORK / 'fixed.md'\n    citation_plan = WORK / 'citation-plan.json'\n    reference_pack = WORK / 'reference-pack.json'\n    profile = WORK / 'profile.json'\n    final = WORK / 'final.md'\n\n    intake.write_text(json.dumps({\n        'paperType': 'degree',\n        'degreeLevel': 'master',\n        'discipline': 'computer-science',\n        'topic': '基于多模态检索增强生成的领域问答系统研究',\n        'style': 'GB/T 7714',\n        'targetWords': 25000,\n        'language': 'zh',\n        'deliveryGoal': 'pdf_with_sources'\n    }, ensure_ascii=False, indent=2), encoding='utf-8')\n\n    citation_plan.write_text(json.dumps({\n        'chapters': [\n            {'chapter': 'experiments', 'claims': [\n                {'claimType': 'baseline comparison', 'recommendedCitations': ['lee2024benchmark'], 'inlineMarker': '[2]'}\n            ]}\n        ]\n    }, ensure_ascii=False, indent=2), encoding='utf-8')\n\n    reference_pack.write_text(json.dumps({\n        'entries': [\n            {'id': 'lee2024benchmark', 'authors': ['Lee'], 'year': 2024}\n        ]\n    }, ensure_ascii=False, indent=2), encoding='utf-8')\n\n    profile.write_text(json.dumps({\n        'style': 'GB/T 7714',\n        'profile': 'cn-thesis-brackets',\n        'bracketStyle': 'square',\n        'zhPunctuationMode': 'fullwidth',\n        'apaParenModeZh': 'fullwidth'\n    }, ensure_ascii=False, indent=2), encoding='utf-8')\n\n    run(['python3', str(ROOT / 'scripts/build_task_sheet.py'), '--input', str(intake), '--out-json', str(task)])\n    run(['python3', str(ROOT / 'scripts/build_figure_table_plan.py'), '--task', str(task), '--citation-plan', str(citation_plan), '--out-json', str(plan)])\n\n    draft.write_text('表 4-1 显示实验结果。\n', encoding='utf-8')\n    run(['python3', str(ROOT / 'scripts/autofix_figure_table_refs.py'), '--plan', str(plan), '--draft', str(draft), '--citation-mode', 'internal-anchor', '--out', str(fixed)])\n    run(['python3', str(ROOT / 'scripts/render_final_citations.py'), '--draft', str(fixed), '--reference-pack', str(reference_pack), '--citation-plan', str(citation_plan), '--citation-profile-json', str(profile), '--style', 'GB/T 7714', '--out', str(final)])\n\n    out = final.read_text(encoding='utf-8')\n    if '[1]' not in out and '[2]' not in out:\n        raise SystemExit(f'Smoke test failed: expected rendered citation marker in final output, got:\n{out}')\n\n    print(json.dumps({'ok': True, 'workdir': str(WORK), 'final': out}, ensure_ascii=False, indent=2))\n\n\nif __name__ == '__main__':\n    main()\n